'use client';

/**
 * LedgerSchema — interactive viewer for a Formance ledger schema.
 *
 * Renders the three parts of a ledger schema — chart of accounts,
 * transactions (Numscript), and queries — in one component, with a tabbed
 * full view plus narrowing props to show a single section, a single
 * transaction, or a single chart subtree.
 *
 *   <LedgerSchema data={schema} />                          full tabbed view
 *   <LedgerSchema data={schema} section="chart" />          just the chart
 *   <LedgerSchema data={schema} tx="CLIENT_DEPOSIT" />      a single transaction
 *   <LedgerSchema data={schema} chart="banks" />            a single chart subtree
 *
 * Data-driven: the schema is passed as a parsed object, not loaded by name.
 * Interpreter / feature-flag pills are predicted from the Numscript source
 * (see `_ledger-schema/numscript`); explicit `interpreter`/`featureFlags`
 * fields on a transaction override the prediction. Host-specific tooling
 * (playground launcher, dev debug strip) is injected via the optional
 * `renderScript*` slots.
 */

import { Check, ChevronRight, Copy } from 'lucide-react';
import { useState, type ReactNode } from 'react';

import { cn } from '@/lib/utils';
import {
  ChartOfAccounts,
  type TChartOfAccountsProps,
  type TChartSegment,
} from '@/registry/default/ui-fragments/_ledger-schema/chart-of-accounts';
import {
  flagShortName,
  inferFlags,
  inferInterpreter,
  normalizeFlags,
  type TInterpreter,
} from '@/registry/default/ui-fragments/_ledger-schema/numscript';
import { Badge } from '@/registry/default/ui/badge';
import { Button } from '@/registry/default/ui/button';
import { CodeSnippet } from '@/registry/default/ui/code/code-snippet';
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/registry/default/ui/collapsible';
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from '@/registry/default/ui/tabs';

export type TLedgerTransaction = {
  description?: string;
  script?: string;
  interpreter?: TInterpreter;
  featureFlags?: string[];
};

export type TLedgerQuery = {
  description?: string;
  resource?: string;
  vars?: unknown;
  params?: unknown;
  body?: unknown;
};

export type TLedgerSchemaData = {
  chart?: Record<string, TChartSegment | null>;
  transactions?: Record<string, TLedgerTransaction>;
  queries?: Record<string, TLedgerQuery>;
};

type TScriptSlots = {
  renderScriptTags?: (code: string) => ReactNode;
  renderScriptActions?: (code: string) => ReactNode;
  renderScriptFooter?: (code: string) => ReactNode;
};

/**
 * Chart-of-accounts display controls forwarded verbatim to the chart view —
 * the single chart subtree, `section="chart"`, and the full view's chart tab.
 * Picked from the chart's own props so the surface stays in sync; all flat and
 * optional, so they're authorable as MDX attributes (e.g. `legend hideToolbar`).
 */
type TChartViewProps = Pick<
  TChartOfAccountsProps,
  | 'defaultOpenDepth'
  | 'defaultExpanded'
  | 'defaultShowDetails'
  | 'hideToolbar'
  | 'legend'
>;

export type TLedgerSchemaProps = {
  data: TLedgerSchemaData;
  /** Show a single section without the tab bar. */
  section?: 'chart' | 'transactions' | 'queries';
  /** Show only this transaction. */
  tx?: string;
  /** Show only this query. */
  query?: string;
  /** Show only this top-level chart subtree. */
  chart?: string;
  /** Pre-stringified YAML source; when provided, adds a "YAML" tab to the full view. */
  yaml?: string;
  className?: string;
} & TChartViewProps &
  TScriptSlots;

const cardClass =
  'not-prose w-full overflow-hidden rounded-md border bg-card text-card-foreground';

export function LedgerSchema({
  data,
  section,
  tx,
  query,
  chart,
  yaml,
  defaultOpenDepth,
  defaultExpanded,
  defaultShowDetails,
  hideToolbar,
  legend,
  className,
  renderScriptTags,
  renderScriptActions,
  renderScriptFooter,
}: TLedgerSchemaProps) {
  const slots: TScriptSlots = {
    renderScriptTags,
    renderScriptActions,
    renderScriptFooter,
  };
  const chartProps: TChartViewProps = {
    defaultOpenDepth,
    defaultExpanded,
    defaultShowDetails,
    hideToolbar,
    legend,
  };

  if (tx && data.transactions?.[tx]) {
    return (
      <TransactionCard
        name={tx}
        tx={data.transactions[tx]}
        slots={slots}
        foldable={false}
        className={className}
      />
    );
  }

  if (query && data.queries?.[query]) {
    return (
      <QueryCard
        name={query}
        query={data.queries[query]}
        foldable={false}
        className={className}
      />
    );
  }

  if (chart && data.chart && Object.hasOwn(data.chart, chart)) {
    return (
      <ChartOfAccounts
        data={{ [chart]: data.chart[chart] ?? null }}
        {...chartProps}
        className={className}
      />
    );
  }

  if (section === 'chart' && data.chart) {
    return (
      <ChartOfAccounts
        data={data.chart}
        {...chartProps}
        className={className}
      />
    );
  }

  if (section === 'transactions' && data.transactions) {
    return (
      <div className={cn(cardClass, 'p-3', className)}>
        <TransactionsView transactions={data.transactions} slots={slots} />
      </div>
    );
  }

  if (section === 'queries' && data.queries) {
    return (
      <div className={cn(cardClass, 'p-3', className)}>
        <QueriesView queries={data.queries} />
      </div>
    );
  }

  return (
    <FullSchemaView
      data={data}
      yaml={yaml}
      chartProps={chartProps}
      className={className}
      slots={slots}
    />
  );
}

// ── Full tabbed view ────────────────────────────────────────

function FullSchemaView({
  data,
  yaml,
  chartProps,
  className,
  slots,
}: {
  data: TLedgerSchemaData;
  yaml?: string;
  chartProps: TChartViewProps;
  className?: string;
  slots: TScriptSlots;
}) {
  const hasContent = !!(data.chart || data.transactions || data.queries);
  const tabs: string[] = [];
  if (data.chart) tabs.push('chart');
  if (data.transactions) tabs.push('transactions');
  if (data.queries) tabs.push('queries');
  if (yaml?.trim()) tabs.push('yaml');
  if (hasContent) tabs.push('json');

  if (tabs.length === 0) {
    return (
      <div
        className={cn(
          cardClass,
          'p-8 text-center text-muted-foreground',
          className
        )}
      >
        No schema content.
      </div>
    );
  }

  const isSingleTab = tabs.length === 1;
  const counts: Record<string, number | undefined> = {
    transactions: data.transactions
      ? Object.keys(data.transactions).length
      : undefined,
    queries: data.queries ? Object.keys(data.queries).length : undefined,
  };

  return (
    <div className={cn(cardClass, className)}>
      <Tabs defaultValue={tabs[0]} className="gap-0">
        <div className="flex items-center border-b bg-muted/40 pr-2">
          <TabsList variant="line" className="-ml-px px-2 pl-0">
            {tabs.map((t) => (
              <TabsTrigger
                key={t}
                value={t}
                className={isSingleTab ? 'after:hidden' : undefined}
              >
                {t}
                {counts[t] != null && (
                  <span className="rounded-full bg-foreground/10 px-1.5 text-[10px] font-normal tabular-nums">
                    {counts[t]}
                  </span>
                )}
              </TabsTrigger>
            ))}
          </TabsList>
          {yaml?.trim() && (
            <CopyButton text={yaml.trim()} label="Copy" className="ml-auto" />
          )}
        </div>

        {data.chart && (
          <TabsContent value="chart" className="p-0">
            <ChartOfAccounts
              data={data.chart}
              {...chartProps}
              className="rounded-none border-0 bg-transparent"
            />
          </TabsContent>
        )}
        {data.transactions && (
          <TabsContent value="transactions" className="p-2">
            <TransactionsView transactions={data.transactions} slots={slots} />
          </TabsContent>
        )}
        {data.queries && (
          <TabsContent value="queries" className="p-2">
            <QueriesView queries={data.queries} />
          </TabsContent>
        )}
        {yaml?.trim() && (
          <TabsContent value="yaml" className="p-0">
            <CodeSnippet code={yaml.trim()} language="yaml" bordered={false} />
          </TabsContent>
        )}
        {hasContent && (
          <TabsContent value="json" className="p-0">
            <CodeSnippet
              code={JSON.stringify(data, null, 2)}
              language="json"
              bordered={false}
            />
          </TabsContent>
        )}
      </Tabs>
    </div>
  );
}

// ── Transactions ────────────────────────────────────────────

function TransactionsView({
  transactions,
  slots,
}: {
  transactions: Record<string, TLedgerTransaction>;
  slots: TScriptSlots;
}) {
  return (
    <div className="flex flex-col gap-3">
      {Object.entries(transactions).map(([name, tx]) => (
        <TransactionCard key={name} name={name} tx={tx} slots={slots} />
      ))}
    </div>
  );
}

function TransactionCard({
  name,
  tx,
  slots,
  foldable,
  className,
}: {
  name: string;
  tx: TLedgerTransaction;
  slots: TScriptSlots;
  foldable?: boolean;
  className?: string;
}) {
  const code = tx.script?.trim() ?? '';

  return (
    <SchemaCard
      name={name}
      badges={
        code ? (
          <ScriptTags code={code} tx={tx} render={slots.renderScriptTags} />
        ) : null
      }
      description={tx.description}
      actions={
        code ? (
          <>
            {slots.renderScriptActions?.(code)}
            <CopyButton text={code} />
          </>
        ) : null
      }
      code={code}
      language="numscript"
      footer={code ? slots.renderScriptFooter?.(code) : null}
      foldable={foldable}
      className={className}
    />
  );
}

/**
 * Card shared by transactions and queries: name + badges on the title row,
 * description below it, and a code block. In a list (`foldable`) the title row
 * is a fold trigger with a chevron and the code collapses; for a single item
 * it renders flat with no chevron and the code always shown.
 */
function SchemaCard({
  name,
  badges,
  description,
  actions,
  code,
  language,
  footer,
  defaultOpen = true,
  foldable = true,
  className,
}: {
  name: string;
  badges?: ReactNode;
  description?: string;
  actions?: ReactNode;
  code: string;
  language: 'numscript' | 'json';
  footer?: ReactNode;
  defaultOpen?: boolean;
  foldable?: boolean;
  className?: string;
}) {
  const titleColumn = (
    <div className="min-w-0 flex-1 space-y-1">
      <div className="flex flex-wrap items-center gap-2">
        <span className="font-mono text-sm font-semibold text-foreground">
          {name}
        </span>
        {badges}
      </div>
      {description && (
        <div className="pb-2 text-xs text-muted-foreground">
          {description.replace(/\s+/g, ' ').trim()}
        </div>
      )}
    </div>
  );

  const codeBlock = code && (
    <div className="border-t">
      <CodeSnippet
        code={code}
        language={language}
        bordered={false}
        canCopy={false}
      />
      {footer}
    </div>
  );

  const actionsCluster = actions && (
    <div className="flex shrink-0 items-center gap-1">{actions}</div>
  );

  const cardClassName = cn(
    'overflow-hidden rounded-md border bg-card',
    className
  );

  if (!foldable) {
    return (
      <div className={cardClassName}>
        <div className="flex items-start gap-2 px-2 pt-2">
          {titleColumn}
          {actionsCluster}
        </div>
        {codeBlock}
      </div>
    );
  }

  return (
    <Collapsible defaultOpen={defaultOpen} className={cardClassName}>
      <div className="flex items-start gap-2 px-2 pt-2">
        <CollapsibleTrigger className="group flex min-w-0 flex-1 items-start gap-2 text-left">
          <ChevronRight className="mt-0.5 size-3.5 shrink-0 text-muted-foreground transition-transform group-data-[state=open]:rotate-90" />
          {titleColumn}
        </CollapsibleTrigger>
        {actionsCluster}
      </div>
      {code && <CollapsibleContent>{codeBlock}</CollapsibleContent>}
    </Collapsible>
  );
}

function ScriptTags({
  code,
  tx,
  render,
}: {
  code: string;
  tx: TLedgerTransaction;
  render?: (code: string) => ReactNode;
}) {
  if (render) return <>{render(code)}</>;

  const flags =
    tx.featureFlags && tx.featureFlags.length
      ? normalizeFlags(tx.featureFlags)
      : inferFlags(code);
  const interpreter = tx.interpreter ?? inferInterpreter(flags);

  return (
    <span className="flex shrink-0 flex-wrap items-center gap-1">
      <Badge
        variant={interpreter === 'experimental' ? 'amber' : 'secondary'}
        size="sm"
      >
        {interpreter}
      </Badge>
      {flags.map((f) => (
        <Badge key={f} variant="violet" size="sm" className="normal-case">
          {flagShortName(f)}
        </Badge>
      ))}
    </span>
  );
}

// ── Queries ─────────────────────────────────────────────────

function QueriesView({ queries }: { queries: Record<string, TLedgerQuery> }) {
  return (
    <div className="flex flex-col gap-3">
      {Object.entries(queries).map(([name, q]) => (
        <QueryCard key={name} name={name} query={q} />
      ))}
    </div>
  );
}

function QueryCard({
  name,
  query,
  foldable,
  className,
}: {
  name: string;
  query: TLedgerQuery;
  foldable?: boolean;
  className?: string;
}) {
  const body = query.body != null ? JSON.stringify(query.body, null, 2) : '';

  return (
    <SchemaCard
      name={name}
      badges={
        query.resource ? (
          <Badge variant="secondary" size="sm">
            {query.resource}
          </Badge>
        ) : null
      }
      description={query.description}
      actions={body ? <CopyButton text={body} /> : null}
      code={body}
      language="json"
      foldable={foldable}
      className={className}
    />
  );
}

// ── Copy button ─────────────────────────────────────────────
// Matches the design-system outline icon button used by ApiSnippet, so the
// copy / play actions read consistently across both fragments.

function CopyButton({
  text,
  label,
  className,
}: {
  text: string;
  label?: string;
  className?: string;
}) {
  const [copied, setCopied] = useState(false);

  return (
    <Button
      variant="outline"
      size={label ? 'sm' : 'icon-sm'}
      aria-label="Copy"
      className={cn(
        'text-muted-foreground',
        label && 'gap-1.5 [&>svg]:size-3.5',
        className
      )}
      onClick={async (e) => {
        e.stopPropagation();
        await navigator.clipboard.writeText(text.trim());
        setCopied(true);
        setTimeout(() => setCopied(false), 1500);
      }}
    >
      {copied ? <Check /> : <Copy />}
      {label && <span>{copied ? 'Copied' : label}</span>}
    </Button>
  );
}

'use client';

import {
  ChevronsDownUp,
  ChevronsUpDown,
  Coins,
  Eye,
  EyeOff,
  Folder,
  FolderOpen,
} from 'lucide-react';
import * as React from 'react';

import { cn } from '@/lib/utils';
import { Badge } from '@/registry/default/ui/badge';
import { Button } from '@/registry/default/ui/button';
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/registry/default/ui/collapsible';
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from '@/registry/default/ui/tooltip';

export type TChartSegment = {
  '.self'?: Record<string, never>;
  '.pattern'?: string;
  '.metadata'?: Record<string, { default?: string } | undefined>;
} & {
  [key: string]: unknown;
};

export type TChartOfAccountsProps = {
  data: Record<string, TChartSegment | null>;
  defaultOpenDepth?: number;
  defaultExpanded?: boolean;
  defaultShowDetails?: boolean;
  hideToolbar?: boolean;
  legend?: boolean;
  className?: string;
};

export function ChartOfAccounts({
  data,
  defaultOpenDepth,
  defaultExpanded,
  defaultShowDetails = true,
  hideToolbar = false,
  legend = false,
  className,
}: TChartOfAccountsProps) {
  const entries = Object.entries(data);
  const [expanded, setExpanded] = React.useState<boolean | undefined>(
    defaultExpanded
  );
  const [showDetails, setShowDetails] = React.useState(defaultShowDetails);

  return (
    <div
      className={cn(
        'relative rounded-md border bg-card text-card-foreground px-4 py-3 font-mono text-[13px] leading-6',
        className
      )}
    >
      {!hideToolbar && (
        <div className="absolute right-2.5 top-2.5 flex items-center gap-1">
          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant="outline"
                size="icon-sm"
                aria-label={showDetails ? 'Hide details' : 'Show details'}
                onClick={() => setShowDetails((v) => !v)}
              >
                {showDetails ? <Eye /> : <EyeOff />}
              </Button>
            </TooltipTrigger>
            <TooltipContent>
              {showDetails ? 'Hide details' : 'Show details'}
            </TooltipContent>
          </Tooltip>
          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant="outline"
                size="icon-sm"
                aria-label={expanded === false ? 'Expand all' : 'Collapse all'}
                onClick={() => setExpanded((v) => !(v ?? true))}
              >
                {expanded === false ? <ChevronsUpDown /> : <ChevronsDownUp />}
              </Button>
            </TooltipTrigger>
            <TooltipContent>
              {expanded === false ? 'Expand all' : 'Collapse all'}
            </TooltipContent>
          </Tooltip>
        </div>
      )}
      <div role="tree">
        {entries.map(([name, node], i) => (
          <ChartNode
            key={name}
            name={name}
            node={node}
            depth={0}
            prefix=""
            isLast={i === entries.length - 1}
            defaultOpenDepth={defaultOpenDepth}
            expanded={expanded}
            showDetails={showDetails}
          />
        ))}
      </div>
      {legend && <ChartLegend />}
    </div>
  );
}

function ChartLegend() {
  return (
    <div className="mt-3 flex flex-wrap items-center gap-x-4 gap-y-1.5 border-t pt-3 text-xs text-muted-foreground">
      <span className="flex items-center gap-1.5">
        <Folder className="size-3.5 shrink-0 text-cobalt-500" />
        folder
      </span>
      <span className="flex items-center gap-1.5">
        <Coins className="size-3.5 shrink-0 text-mint-700 dark:text-mint-600" />
        account
      </span>
      <span className="flex items-center gap-1.5">
        <span className="inline-flex items-center gap-0.5">
          <Folder className="size-3.5 shrink-0 text-cobalt-500" />
          <Coins className="size-3.5 shrink-0 text-mint-700 dark:text-mint-600" />
        </span>
        folder + account (.self)
      </span>
      <span className="flex items-center gap-1.5">
        <span
          aria-hidden
          className="shrink-0 select-none font-mono text-gold-500 dark:text-gold-300"
        >
          {'{}'}
        </span>
        parameterized
      </span>
    </div>
  );
}

type TChartNodeProps = {
  name: string;
  node: TChartSegment | null;
  depth: number;
  prefix: string;
  isLast: boolean;
  defaultOpenDepth?: number;
  expanded?: boolean;
  showDetails: boolean;
};

function ChartNode({
  name,
  node,
  depth,
  prefix,
  isLast,
  defaultOpenDepth,
  expanded,
  showDetails,
}: TChartNodeProps) {
  const entries =
    node && typeof node === 'object'
      ? Object.entries(node as Record<string, unknown>)
      : [];
  const meta = entries.filter(([k]) => k.startsWith('.'));
  const children = entries.filter(([k]) => !k.startsWith('.'));

  const isVariable = name.startsWith('$');
  const isSelf = meta.some(([k]) => k === '.self');
  const pattern = meta.find(([k]) => k === '.pattern')?.[1] as
    | string
    | undefined;
  const metadata = meta.find(([k]) => k === '.metadata')?.[1] as
    | Record<string, { default?: string } | undefined>
    | undefined;

  const hasChildren = children.length > 0;
  const isPostable = isSelf || !hasChildren;
  const childPrefix = depth === 0 ? '' : prefix + (isLast ? '   ' : '│  ');
  const connector = depth === 0 ? '' : isLast ? '└─ ' : '├─ ';

  const initialOpen =
    expanded != null
      ? expanded
      : defaultOpenDepth != null
        ? depth < defaultOpenDepth
        : true;
  const [open, setOpen] = React.useState(initialOpen);

  React.useEffect(() => {
    if (expanded != null) setOpen(expanded);
  }, [expanded]);

  const rowContent = (
    <>
      <span className="whitespace-pre">
        {(prefix || connector) && (
          <span aria-hidden className="select-none text-muted-foreground/60">
            {prefix}
            {connector}
          </span>
        )}
        <span
          aria-hidden
          className="inline-flex items-center gap-0.5 align-middle"
        >
          {hasChildren &&
            (open ? (
              <FolderOpen className="size-3.5 shrink-0 text-cobalt-500" />
            ) : (
              <Folder className="size-3.5 shrink-0 text-cobalt-500" />
            ))}
          {isPostable && (
            <Coins className="size-3.5 shrink-0 text-mint-700 dark:text-mint-600" />
          )}
          {isVariable && (
            <span
              aria-hidden
              className="shrink-0 select-none font-mono text-gold-500 dark:text-gold-300"
            >
              {'{}'}
            </span>
          )}
        </span>
      </span>
      <span
        className={cn(
          isVariable ? 'text-gold-500 dark:text-gold-300' : 'text-foreground'
        )}
      >
        {name}
      </span>
      {showDetails && pattern && (
        <Badge
          variant="outline"
          size="sm"
          className="font-mono normal-case text-muted-foreground"
        >
          {pattern}
        </Badge>
      )}
      {isPostable && <span className="sr-only">account</span>}
      {showDetails &&
        metadata &&
        Object.entries(metadata).map(([k, v]) => {
          const def = v?.default;
          if (!def) return null;

          return (
            <Badge key={k} variant="secondary" size="sm">
              {k}={def}
            </Badge>
          );
        })}
    </>
  );

  const rowClass = 'flex items-center gap-1.5';

  if (!hasChildren) {
    return (
      <div className={rowClass} role="treeitem">
        {rowContent}
      </div>
    );
  }

  return (
    <Collapsible open={open} onOpenChange={setOpen}>
      <CollapsibleTrigger
        aria-label={open ? `Collapse ${name}` : `Expand ${name}`}
        className={cn(
          rowClass,
          'w-full text-left rounded-sm hover:bg-muted/40 focus:outline-none focus-visible:ring-2 focus-visible:ring-ring'
        )}
      >
        {rowContent}
      </CollapsibleTrigger>
      <CollapsibleContent>
        {children.map(([key, val], i) => (
          <ChartNode
            key={key}
            name={key}
            node={(val ?? null) as TChartSegment | null}
            depth={depth + 1}
            prefix={childPrefix}
            isLast={i === children.length - 1}
            defaultOpenDepth={defaultOpenDepth}
            expanded={expanded}
            showDetails={showDetails}
          />
        ))}
      </CollapsibleContent>
    </Collapsible>
  );
}

/**
 * Local static analysis of a Numscript snippet — vendored, dependency-free.
 *
 * Ported from `@formance/numscript-engine` (the docs build pipeline). We
 * don't ship a Numscript parser in JS, but we can detect which experimental
 * features a snippet uses from stable, lexical signals: each feature has a
 * recognisable keyword or syntactic shape. The detector is conservative — it
 * errs toward "needs the flag" when uncertain.
 *
 * To keep the lexical pass robust, comments are stripped and string literals
 * are masked first so their contents can't trigger a false positive.
 */

export type TFeatureFlag =
  | 'experimental-overdraft-function'
  | 'experimental-get-asset-function'
  | 'experimental-get-amount-function'
  | 'experimental-oneof'
  | 'experimental-account-interpolation'
  | 'experimental-mid-script-function-call'
  | 'experimental-asset-colors'
  | 'experimental-asset-scaling';

export type TFeatureFlagSpec = {
  id: TFeatureFlag;
  /** Human-readable short name, used in pills/chips. */
  short: string;
};

export type TInterpreter = 'machine' | 'experimental';

export const FEATURE_FLAGS: readonly TFeatureFlagSpec[] = [
  { id: 'experimental-overdraft-function', short: 'overdraft()' },
  { id: 'experimental-oneof', short: 'oneof' },
  { id: 'experimental-account-interpolation', short: 'account interpolation' },
  {
    id: 'experimental-mid-script-function-call',
    short: 'mid-script function call',
  },
  { id: 'experimental-get-asset-function', short: 'get_asset()' },
  { id: 'experimental-get-amount-function', short: 'get_amount()' },
  { id: 'experimental-asset-colors', short: 'asset colors' },
  { id: 'experimental-asset-scaling', short: 'asset scaling' },
] as const;

const FLAG_IDS = new Set(FEATURE_FLAGS.map((f) => f.id));
const FLAG_INDEX = new Map(FEATURE_FLAGS.map((f, i) => [f.id, i]));
const FLAG_SHORT = new Map(FEATURE_FLAGS.map((f) => [f.id, f.short]));

function isFeatureFlag(id: string): id is TFeatureFlag {
  return FLAG_IDS.has(id as TFeatureFlag);
}

/** Sort a flag set into canonical order (the order listed above). */
export function normalizeFlags(flags: readonly string[]): TFeatureFlag[] {
  const seen = new Set<TFeatureFlag>();
  for (const f of flags) if (isFeatureFlag(f)) seen.add(f);

return [...seen].sort(
    (a, b) => (FLAG_INDEX.get(a) ?? 0) - (FLAG_INDEX.get(b) ?? 0)
  );
}

/** Short, human-readable label for a flag (falls back to stripping the prefix). */
export function flagShortName(flag: TFeatureFlag): string {
  return FLAG_SHORT.get(flag) ?? flag.replace(/^experimental-/, '');
}

const SHEBANGS: ReadonlyArray<{ flag: TFeatureFlag; re: RegExp }> = [
  // overdraft() the function (the `allowing … overdraft` directive is machine-compatible).
  { flag: 'experimental-overdraft-function', re: /\boverdraft\s*\(/ },
  { flag: 'experimental-oneof', re: /\boneof\b/ },
  // `@foo:$var:bar` or `@$var` — a `$var` segment inside an `@` account literal.
  {
    flag: 'experimental-account-interpolation',
    re: /@[A-Za-z0-9_:-]*\$[A-Za-z_]/,
  },
  { flag: 'experimental-get-asset-function', re: /\bget_asset\s*\(/ },
  { flag: 'experimental-get-amount-function', re: /\bget_amount\s*\(/ },
  // `vars { monetary $x = fn(...) }` — a function call on the RHS inside the vars block.
  {
    flag: 'experimental-mid-script-function-call',
    re: /\bvars\s*\{[^}]*=\s*[A-Za-z_][A-Za-z0-9_]*\s*\(/s,
  },
  // `@account \ "GRANT"` color restriction OR `[USD/2#red 100]` asset-literal color suffix.
  {
    flag: 'experimental-asset-colors',
    re: /(?:@[A-Za-z0-9_:$-]+\s*\\\s*"[^"]*")|(?:\[[A-Z][A-Z0-9]*\/\d+#[A-Za-z0-9_-]+)/,
  },
  // `[USD/2 -> USD/4 …]` scale conversion.
  {
    flag: 'experimental-asset-scaling',
    re: /\[[A-Z][A-Z0-9]*\/\d+\s*->\s*[A-Z]/,
  },
];

/** Strip line + block comments, replacing them with spaces (preserves offsets). */
function stripComments(source: string): string {
  return source
    .replace(/\/\*[\s\S]*?\*\//g, (m) => ' '.repeat(m.length))
    .replace(/\/\/[^\n]*/g, (m) => ' '.repeat(m.length));
}

/** Mask string-literal contents with spaces (preserves offsets + quote chars). */
function maskStrings(source: string): string {
  return source.replace(
    /"([^"\\]|\\.)*"/g,
    (m) => `"${' '.repeat(m.length - 2)}"`
  );
}

/** Mask strings FIRST so a `"// foo"` literal can't be misread as a comment. */
function sanitize(script: string): string {
  return stripComments(maskStrings(script));
}

/**
 * Parse a `#![feature("a", "b", …)]` declaration at the top of a snippet.
 * Comment-stripped but NOT string-masked: the flag ids live inside `"…"`.
 */
function extractShebangFlags(script: string): TFeatureFlag[] {
  const match = stripComments(script).match(
    /#!\[feature\s*\(\s*([^)]+)\s*\)\s*\]/
  );
  if (!match?.[1]) return [];
  const ids = [...match[1].matchAll(/"([^"]+)"/g)].map((m) => m[1]!);

return normalizeFlags(ids);
}

/** Minimum feature-flag set a snippet needs, inferred from lexical signals. */
export function inferFlags(script: string): TFeatureFlag[] {
  const sanitized = sanitize(script);
  const hits = new Set<TFeatureFlag>();
  for (const f of extractShebangFlags(script)) hits.add(f);
  for (const { flag, re } of SHEBANGS) {
    if (re.test(sanitized)) hits.add(flag);
  }

return normalizeFlags([...hits]);
}

/**
 * Conservative interpreter guess: a snippet that needs no experimental flag
 * runs on the `machine` interpreter, otherwise it's `experimental`. This
 * mirrors the docs' non-validated `useSnippet` path.
 */
export function inferInterpreter(flags: readonly TFeatureFlag[]): TInterpreter {
  return flags.length === 0 ? 'machine' : 'experimental';
}
